template&lt;int a&gt; void foo(const char(&amp;p)[a])&#123;//..&#125; const char(&amp;p)[a]是什么意思？ 是在看我的一位室友的时候发现了这个非常非常高级的用法，我也是在Stack Overflow等平台上查了好多了解相关的知识。以下的代码其实，也是我室友给的，但是他写得真的很好，我也要留一份（） #if 1 #include &lt;iostream&gt; using namespace std; //int* p ; int (&amp;i_ref)[] ; char* p; char (&amp;c_ref)[] void fooCharP(char* str1, const char* str2) &#123; std::cout &lt;&lt; &quot;char pointer:
&quot;; std::cout &lt;&lt; &quot;char*: &quot; &lt;&lt; sizeof(str1) / sizeof(str1[0]) &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;const char*: &quot; &lt;&lt; sizeof(str2) / sizeof(str2[0]) &lt;&lt; &quot;
&quot;; &#125; void fooCharP_Ref(char* (&amp;str1), const char* (&amp;str2)) &#123; std::cout &lt;&lt; &quot;char pointer reference:
&quot;; std::cout &lt;&lt; &quot;char* ref: &quot; &lt;&lt; sizeof(str1) / sizeof(str1[0]) &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;const char* ref: &quot; &lt;&lt; sizeof(str2) / sizeof(str2[0]) &lt;&lt; &quot;
&quot;; &#125; template &lt;int size&gt; void fooCharArrayRef(char (&amp;str1)[size], const char (&amp;str2)[size]) &#123; std::cout &lt;&lt; &quot;char array reference:
&quot;; std::cout &lt;&lt; &quot;char (&amp;str1)[]: &quot; &lt;&lt; sizeof(str1) / sizeof(str1[0]) &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;const char (&amp;str2)[]: &quot; &lt;&lt; sizeof(str2) / sizeof(str2[0]) &lt;&lt; &quot;
&quot;; &#125; void fooIntP(int* int1) &#123; std::cout &lt;&lt; &quot;int pointer:
&quot; ; std::cout &lt;&lt; &quot;int*: &quot; &lt;&lt; sizeof(int1) / sizeof(int1[0]) &lt;&lt; &quot;
&quot;; &#125; void fooIntP_Ref(int* (&amp;str1)) &#123; std::cout &lt;&lt; &quot;int pointer reference:
&quot;; std::cout &lt;&lt; &quot;int* ref: &quot; &lt;&lt; sizeof(str1) / sizeof(str1[0]) &lt;&lt; &quot;
&quot;; &#125; template &lt;int size&gt; void fooIntArrayRef(int(&amp;str1)[size]) &#123; std::cout &lt;&lt; &quot;int array reference:
&quot;; std::cout &lt;&lt; &quot;int (&amp;int1)[]: &quot; &lt;&lt; sizeof(str1) / sizeof(str1[0]) &lt;&lt; &quot;
&quot;; &#125; int main() &#123; char* pChar = new char[6]; for (int i = 0; i &lt; 5; i++) &#123; pChar[i] = &#39;2&#39;; &#125; pChar[5] = &#39;\0&#39;; const char* constPChar = &quot;Main Voice&quot;; char aChar[] = &quot;Voice Main&quot;; const char constAChar[] = &quot;Voice Main&quot;; int* pInt = new int[8]; for (int i = 0; i &lt; 8; i++) &#123; pInt[i] = 2; &#125; int arrInt[] = &#123; 1,2,3,4,5,6 &#125;; std::cout &lt;&lt; &quot;the correct length: char:6, const char:11, int: 8, int array: 6
&quot;; std::cout &lt;&lt; &quot;Begin:
&quot;; std::cout &lt;&lt; &quot;STRING:
&quot;; fooCharP(pChar, constPChar); std::cout &lt;&lt; &quot;=====
&quot;; fooCharP_Ref(pChar, constPChar); std::cout &lt;&lt; &quot;=====
&quot;; fooCharArrayRef(aChar, constAChar); std::cout &lt;&lt; &quot;
INT:
&quot;; fooIntP(pInt); std::cout &lt;&lt; &quot;=====
&quot;; fooIntP_Ref(pInt); std::cout &lt;&lt; &quot;=====
&quot;; fooIntArrayRef(arrInt); std::cout &lt;&lt; &quot;end
&quot;; std::cin.get(); delete pInt; delete pChar; return 0; &#125; #endif 简单地说，在传参时，如果直接以char*传参，那么在进入函数时，原先的数组会degenerate，即从数组退化为指针（节省空间），因此，此时对其进行sizeof，求得的值也是这个指针而非数组的大小，这个大小仅仅由机子自身的硬件条件决定。而如果采用const char(&amp;p)[a]的话，会有以下好处： 整个char数组不会作为指针，而是作为数组被引用 因而，sizeof可以获得整个数组的长度 template会动态编译，自动推断a的大小，由于已经知道了数组的长度，因此该函数可以自动推断出字符串的长度 const确保可以引用右值，同时不会修改源字符串内容 传入NULL会报错，避免了char*的缺陷
